#!/bin/bash
# Claude Code 指纹清理工具
# 自动扫描并清理代码中的 Anthropic 指纹，避免 GitHub 溯源
# 用法: ./clean-claude-fingerprints.sh [目录路径]

set -euo pipefail

TARGET_DIR="${1:-.}"
DRY_RUN="${2:-}"

# 颜色定义
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

# Claude Code 指纹模式
PATTERNS=(
    # 生成标记
    "Generated by Claude Code"
    "Generated with Claude Code"
    "Created by Claude Code"
    "Created with Claude Code"
    "Claude Code generated"
    "AI-generated by Claude"

    # 特殊注释模式
    "<!-- claude:"
    "<!-- claude-code:"
    "// claude:"
    "# claude:"
    "/* claude:"

    # 元数据标记
    "claude-version:"
    "claude-model:"
    "claude-session:"
    "anthropic-session:"

    # 特定代码风格（可疑）
    "# Assistant: Claude"
    "# Model: Claude"
    "# Tool: Claude Code"

    # 时间戳标记（部分泄露版特有）
    "# Generated at:"
    "# Timestamp:"
)

# 文件扩展名过滤
FILE_EXTENSIONS=(
    "*.py" "*.js" "*.ts" "*.jsx" "*.tsx"
    "*.java" "*.go" "*.rs" "*.cpp" "*.c"
    "*.md" "*.txt" "*.yaml" "*.yml" "*.json"
    "*.html" "*.css" "*.scss" "*.sql"
)

# 构建 find 命令的 -name 参数
NAME_ARGS=()
for ext in "${FILE_EXTENSIONS[@]}"; do
    if [ ${#NAME_ARGS[@]} -eq 0 ]; then
        NAME_ARGS+=("-name" "$ext")
    else
        NAME_ARGS+=("-o" "-name" "$ext")
    fi
done

echo -e "${BLUE}🔍 Claude Code 指纹清理工具${NC}"
echo "========================"
echo -e "目标目录: ${YELLOW}$TARGET_DIR${NC}"
echo ""

# 统计变量
TOTAL_FILES=0
FINGERPRINT_FILES=0
CLEANED_FILES=0

# 扫描函数
scan_fingerprints() {
    local file="$1"
    local found=0

    for pattern in "${PATTERNS[@]}"; do
        if grep -q "$pattern" "$file" 2>/dev/null; then
            if [ $found -eq 0 ]; then
                echo -e "${RED}⚠️  发现指纹: $file${NC}"
                found=1
            fi
            echo -e "   ${YELLOW}匹配: $pattern${NC}"
            grep -n "$pattern" "$file" 2>/dev/null | head -3 | sed 's/^/   /'
        fi
    done

    return $found
}

# 清理函数
clean_file() {
    local file="$1"
    local temp_file="${file}.tmp"

    # 创建备份
    cp "$file" "${file}.bak"

    # 逐行清理
    while IFS= read -r line || [[ -n "$line" ]]; do
        local skip=0
        for pattern in "${PATTERNS[@]}"; do
            if echo "$line" | grep -q "$pattern"; then
                skip=1
                break
            fi
        done

        if [ $skip -eq 0 ]; then
            echo "$line" >> "$temp_file"
        fi
    done < "$file"

    # 替换原文件
    mv "$temp_file" "$file"
    rm -f "${file}.bak"
}

# 主逻辑
echo -e "${BLUE}📋 扫描模式: ${DRY_RUN:+模拟运行 (不修改文件)}${NC}"
echo ""

# 遍历文件
while IFS= read -r -d '' file; do
    TOTAL_FILES=$((TOTAL_FILES + 1))

    if scan_fingerprints "$file"; then
        FINGERPRINT_FILES=$((FINGERPRINT_FILES + 1))

        if [ -z "$DRY_RUN" ]; then
            echo -e "${GREEN}🧹 清理中...${NC}"
            clean_file "$file"
            CLEANED_FILES=$((CLEANED_FILES + 1))
            echo -e "${GREEN}✅ 已清理${NC}"
        else
            echo -e "${YELLOW}💡 模拟模式: 跳过清理${NC}"
        fi
        echo ""
    fi
done < <(find "$TARGET_DIR" -type f \( "${NAME_ARGS[@]}" \) -print0 2>/dev/null)

# 报告
echo "========================"
echo -e "${BLUE}📊 扫描报告${NC}"
echo "========================"
echo -e "扫描文件总数: ${YELLOW}$TOTAL_FILES${NC}"
echo -e "发现指纹文件: ${RED}$FINGERPRINT_FILES${NC}"
if [ -z "$DRY_RUN" ]; then
    echo -e "已清理文件数: ${GREEN}$CLEANED_FILES${NC}"
fi

echo ""
if [ $FINGERPRINT_FILES -gt 0 ]; then
    echo -e "${YELLOW}⚠️  建议: 提交前运行此工具，确保代码无 Claude 指纹${NC}"
else
    echo -e "${GREEN}✅ 未发现 Claude Code 指纹${NC}"
fi

echo ""
echo -e "${BLUE}💡 使用提示:${NC}"
echo "  模拟运行 (不修改): ./clean-claude-fingerprints.sh /path/to/project --dry-run"
echo "  实际清理: ./clean-claude-fingerprints.sh /path/to/project"
